from flask import Flask, jsonify
import pymemcache

app = Flask(__name__)

# Connect to Memcached at localhost:11211 using the pymemcache library
cache = pymemcache.Client(('localhost', 11211))

# Define a function to cache database query results
def cache_db_query(key, func):
    # Check if the result is already cached
    result = cache.get(key)
    if result is not None:
        return jsonify(result)
    
    # If not, execute the function and cache the result
    else:
        result = func()
        cache.set(key, result, 60 * 10)  # 10 minutes TTL
        return jsonify(result)

# Define a function to cache API responses
def cache_api_response(key, func):
    # Check if the response is already cached
    response = cache.get(key)
    if response is not None:
        return jsonify(response)
    
    # If not, execute the function and cache the response
    else:
        response = func()
        cache.set(key, response, 60 * 10)  # 10 minutes TTL
        return jsonify(response)

# Use the cached database query results for the API responses
@app.route('/api/users', methods=['GET'])
def get_users():
    key = 'users'
    users = cache_db_query(key, lambda: [user.to_json() for user in User.objects.all()])
    return jsonify({'users': users})

